wire [31 : 0]  keymem_sboxw;

reg [31 : 0]   muxed_sboxw;
wire [31 : 0]  new_sboxw;


//----------------------------------------------------------------
// Instantiations.
//----------------------------------------------------------------
aes_encipher_block enc_block(
                             .clk(clk),
                             .reset_n(reset_n),

                             .next(enc_next),

                             .keylen(keylen),
                             .round(enc_round_nr),
                             .round_key(round_key),

                             .sboxw(enc_sboxw),
                             .new_sboxw(new_sboxw),

                             .block(block),
                             .new_block(enc_new_block),
                             .ready(enc_ready)
                            );


aes_decipher_block dec_block(
                             .clk(clk),
                             .reset_n(reset_n),

                             .next(dec_next),

                             .keylen(keylen),
                             .round(dec_round_nr),
                             .round_key(round_key),

                             .block(block),
                             .new_block(dec_new_block),
                             .ready(dec_ready)
                            );


aes_key_mem keymem(
                   .clk(clk),
                   .reset_n(reset_n),

                   .key(key),
                   .keylen(keylen),
                   .init(init),

                   .round(muxed_round_nr),
                   .round_key(round_key),
                   .ready(key_ready),

                   .sboxw(keymem_sboxw),
                   .new_sboxw(new_sboxw)
                  );


aes_sbox sbox_inst(.sboxw(muxed_sboxw), .new_sboxw(new_sboxw));


//----------------------------------------------------------------
// Concurrent connectivity for ports etc.
//----------------------------------------------------------------
assign ready        = ready_reg;

//----------------------------------------------------------------
// sbox_mux
//
// Controls which of the encipher datapath or the key memory
// that gets access to the sbox.
//----------------------------------------------------------------
always @*
  begin : sbox_mux
    if (init_state)
      begin
        muxed_sboxw = keymem_sboxw;
      end
    else
      begin
        muxed_sboxw = enc_sboxw;
      end
  end // sbox_mux


//----------------------------------------------------------------
// encdex_mux
//
// Controls which of the datapaths that get the next signal, have
// access to the memory as well as the block processing result.
//----------------------------------------------------------------
always @*
  begin : encdec_mux
    enc_next = 1'b0;
    dec_next = 1'b0;
